export const ModeVsCondition = {
  name: 'Mode vs condition',
  render: () => {
    let reducedMotion = false;

    const el = document.createElement('div');
    el.innerHTML = `
      <style>
        ${baseStyles}
        .play-btn {
          padding: 6px 14px; background: #111; color: #fff;
          font-size: 11px; font-weight: 600; border-radius: 5px;
          cursor: pointer; border: none; font-family: inherit;
        }
        .play-btn:hover { background: #333; }
        .section-label {
          font-size: 10px; font-weight: 600; color: #aaa;
          text-transform: uppercase; letter-spacing: 0.08em; margin-bottom: 8px;
        }
      </style>
      <div class="page">
        <div class="page-title">Motion / Reduced Motion</div>
        <div class="page-subtitle">Mode vs condition</div>
        <div class="page-description">
          The mode approach swaps token values (400ms → 1ms). Motion still occurs — in some cases,
          faster movement is more disorienting. The condition approach removes animation categories
          entirely and uses only opacity changes for meaningful content transitions.
        </div>
        <div class="toggle-bar">
          <button class="toggle-switch" id="mainToggle" aria-pressed="false"></button>
          <span class="toggle-label">Simulate prefers-reduced-motion</span>
          <span class="toggle-status" id="toggleStatus">off</span>
        </div>
        <div class="two-col">
          <!-- Left: Mode (wrong) -->
          <div class="panel panel-wrong">
            <div>
              <div class="panel-title">Mode approach</div>
              <div class="panel-subtitle">Value swap — marked as incorrect in this chapter.</div>
            </div>
            <div class="section-label">Token values</div>
            <div class="token-row">
              <span class="token-name">motion.duration.slow</span>
              <span class="token-val" id="modeVal">400ms</span>
            </div>
            <div class="token-row">
              <span class="token-name">motion.easing.enter</span>
              <span class="token-val">cubic-bezier(0,0,0.2,1)</span>
            </div>
            <div class="section-label">Reference element</div>
            <div style="display:flex;align-items:center;gap:12px;">
              <div class="ref-element" id="modeBox">ref</div>
              <button class="play-btn" id="modePlayBtn">Play</button>
            </div>
            <div class="problem-note" id="modeNote">
              Motion still occurs. Fast movement (1ms) can be more disorienting than slow movement
              for users with vestibular disorders. The semantics of "entering" are preserved but
              the behavior contract is broken.
            </div>
          </div>

          <!-- Right: Condition (correct) -->
          <div class="panel panel-right">
            <div>
              <div class="panel-title">Condition approach</div>
              <div class="panel-subtitle">Structural reduction — no-op categories under reduced motion.</div>
            </div>
            <div class="section-label">Token categories</div>
            <div class="token-row">
              <span class="token-name">motion.duration.*</span>
              <span class="token-val" id="condDuration">active</span>
            </div>
            <div class="token-row">
              <span class="token-name">motion.easing.*</span>
              <span class="token-val" id="condEasing">active</span>
            </div>
            <div class="token-row">
              <span class="token-name">motion.transition.enter</span>
              <span class="token-val" id="condTransition">opacity only if meaningful</span>
            </div>
            <div class="section-label">Reference element</div>
            <div style="display:flex;align-items:center;gap:12px;">
              <div class="ref-element" id="condBox">ref</div>
              <button class="play-btn" id="condPlayBtn">Play</button>
            </div>
            <div class="condition-note" id="condNote">
              Under the condition: no translateY, no scale. Duration and easing categories
              are irrelevant — no animation occurs. Only opacity transitions that convey
              meaningful state change (element appears/disappears) survive.
            </div>
          </div>
        </div>
      </div>
    `;

    const toggle = el.querySelector('#mainToggle');
    const status = el.querySelector('#toggleStatus');
    const modeVal = el.querySelector('#modeVal');
    const condDuration = el.querySelector('#condDuration');
    const condEasing = el.querySelector('#condEasing');
    const condTransition = el.querySelector('#condTransition');
    const modeBox = el.querySelector('#modeBox');
    const condBox = el.querySelector('#condBox');
    const modePlayBtn = el.querySelector('#modePlayBtn');
    const condPlayBtn = el.querySelector('#condPlayBtn');

    function applyState() {
      if (reducedMotion) {
        toggle.classList.add('on');
        toggle.setAttribute('aria-pressed', 'true');
        status.textContent = 'on (simulated)';
        status.classList.add('on');
        modeVal.textContent = '1ms';
        modeVal.style.color = '#cc2200';
        condDuration.textContent = 'no-op';
        condDuration.classList.add('struck');
        condEasing.textContent = 'no-op';
        condEasing.classList.add('struck');
        condTransition.textContent = 'opacity only — instant';
      } else {
        toggle.classList.remove('on');
        toggle.setAttribute('aria-pressed', 'false');
        status.textContent = 'off';
        status.classList.remove('on');
        modeVal.textContent = '400ms';
        modeVal.style.color = '';
        condDuration.textContent = 'active';
        condDuration.classList.remove('struck');
        condEasing.textContent = 'active';
        condEasing.classList.remove('struck');
        condTransition.textContent = 'opacity only if meaningful';
      }
    }

    toggle.addEventListener('click', () => {
      reducedMotion = !reducedMotion;
      applyState();
    });

    modePlayBtn.addEventListener('click', () => {
      if (modePlayBtn.disabled) return;
      modePlayBtn.disabled = true;
      const duration = reducedMotion ? 1 : 400;
      modeBox.style.opacity = '0';
      modeBox.style.transform = 'translateY(12px)';
      const anim = modeBox.animate(
        [
          { opacity: 0, transform: 'translateY(12px)' },
          { opacity: 1, transform: 'translateY(0)' },
        ],
        { duration, easing: 'cubic-bezier(0,0,0.2,1)', fill: 'forwards' }
      );
      anim.onfinish = () => { modePlayBtn.disabled = false; };
    });

    condPlayBtn.addEventListener('click', () => {
      if (condPlayBtn.disabled) return;
      condPlayBtn.disabled = true;
      condBox.style.opacity = '0';
      condBox.style.transform = 'none';
      let anim;
      if (reducedMotion) {
        // Opacity only, instant (1ms duration)
        anim = condBox.animate(
          [{ opacity: 0 }, { opacity: 1 }],
          { duration: 1, fill: 'forwards' }
        );
      } else {
        anim = condBox.animate(
          [
            { opacity: 0, transform: 'translateY(12px)' },
            { opacity: 1, transform: 'translateY(0)' },
          ],
          { duration: 400, easing: 'cubic-bezier(0,0,0.2,1)', fill: 'forwards' }
        );
      }
      anim.onfinish = () => { condPlayBtn.disabled = false; };
    });

    applyState();
    return el;
  },
};

